const p = $input.first().json.body || $input.first().json;
const ctx = p.context || {};
const summary = ctx.summary || {};
const state = ctx.state || {};
const agent = p.agent || {};
const systemMessage = agent.prompt || 'Eres un asistente virtual.';
const parts = [];
parts.push('Mensaje del cliente: ' + ((p.message && p.message.content) || ''));
const conv = p.conversation || {};
parts.push('Cliente: ' + (conv.customerName || '') + ' (' + (conv.customerPhone || '') + ')');
if (summary.text) parts.push('Resumen de la conversacion: ' + summary.text);
if (state && Object.keys(state).length) parts.push('Estado actual: ' + JSON.stringify(state));
const agentInput = parts.join('\n');
return [{ json: {
  systemMessage: systemMessage,
  agentInput: agentInput,
  _ctx: {
    correlationId: p.correlationId,
    tenantId: (p.business || {}).tenantId,
    chatId: conv.chatId,
    customerId: conv.customerId,
    channel: p.channel,
    callbackUrl: p.callbackUrl,
    refreshSummary: !!ctx.refreshSummary,
    summaryVersion: summary.version || 0,
    businessName: (p.business || {}).name,
    message: (p.message && p.message.content) || ''
  }
}}];

const sys = $json.systemMessage || '';
const inp = ($json.agentInput || '').toLowerCase();
let intent = 'triage';
let reply;
if (inp.includes('limpieza') || inp.includes('agendar') || inp.includes('cita')) { intent = 'schedule'; reply = 'Con gusto agendo tu cita. Tengo espacio el jueves 4pm, confirmas?'; }
else if (inp.includes('confirmo')) { intent = 'confirm_booking'; reply = 'Listo, tu cita queda confirmada.'; }
else { reply = 'Hola, soy tu asistente. En que te ayudo?'; }
// Prueba de prompt per-user: marca con inicio del systemMessage (incluye nombre del negocio)
reply += ' [prompt:' + sys.slice(0, 55).replace(/\n/g, ' ') + ']';
return [{ json: { intent: intent, reply: reply, nombre: '', correo: '', servicio: '', descripcion: inp.slice(0, 40), fecha_hora: '', folio: '', ticket_correcto: null } }];

const parsed = $json;
const ctx = $('Adaptar').first().json._ctx;
const intent = parsed.intent || 'triage';
const content = parsed.reply || '';
const statePatch = { stage: intent };
['nombre', 'correo', 'servicio', 'descripcion', 'fecha_hora'].forEach(function (k) { if (parsed[k]) statePatch[k] = parsed[k]; });
const memory = { summary: null, statePatch: statePatch };
if (ctx.refreshSummary) memory.summary = { text: 'Resumen: ' + (parsed.descripcion || ctx.message || ''), version: (ctx.summaryVersion || 0) + 1 };
const payload = {
  correlationId: ctx.correlationId,
  tenantId: ctx.tenantId,
  chatId: ctx.chatId,
  customerId: ctx.customerId,
  channel: ctx.channel,
  reply: { type: 'TEXT', content: content, mediaUrl: null },
  memory: memory,
  handoff: intent === 'human_escalation'
};
return [{ json: { callbackUrl: ctx.callbackUrl, payload: payload } }];
